342	                    </SelectPopup>
343	                  </Select>
344	                  <span className="text-xs text-muted-foreground">
345	                    {APP_SERVICE_TIER_OPTIONS.find((option) => option.value === codexServiceTier)
346	                      ?.description ?? "Use Codex defaults without forcing a service tier."}
347	                  </span>
348	                </label>
349	
350	                {MODEL_PROVIDER_SETTINGS.map((providerSettings) => {
351	                  const provider = providerSettings.provider;
352	                  const customModels = getCustomModelsForProvider(settings, provider);
353	                  const customModelInput = customModelInputByProvider[provider];
354	                  const customModelError = customModelErrorByProvider[provider] ?? null;
355	                  return (
356	                    <div
357	                      key={provider}
358	                      className="rounded-xl border border-border bg-background/50 p-4"
359	                    >
360	                      <div className="mb-4">
361	                        <h3 className="text-sm font-medium text-foreground">
362	                          {providerSettings.title}
363	                        </h3>
364	                        <p className="mt-1 text-xs text-muted-foreground">
365	                          {providerSettings.description}
366	                        </p>
367	                      </div>
368	
369	                      <div className="space-y-4">
370	                        <div className="flex flex-col gap-3 sm:flex-row sm:items-start">
371	                          <label
372	                            htmlFor={`custom-model-slug-${provider}`}
373	                            className="block flex-1 space-y-1"
374	                          >
375	                            <span className="text-xs font-medium text-foreground">
376	                              Custom model slug
377	                            </span>
378	                            <Input
379	                              id={`custom-model-slug-${provider}`}
380	                              value={customModelInput}
381	                              onChange={(event) => {
382	                                const value = event.target.value;
383	                                setCustomModelInputByProvider((existing) => ({
384	                                  ...existing,
385	                                  [provider]: value,
386	                                }));
387	                                if (customModelError) {
388	                                  setCustomModelErrorByProvider((existing) => ({
389	                                    ...existing,
390	                                    [provider]: null,
391	                                  }));
392	                                }
393	                              }}
394	                              onKeyDown={(event) => {
395	                                if (event.key !== "Enter") return;
396	                                event.preventDefault();
397	                                addCustomModel(provider);
398	                              }}
399	                              placeholder={providerSettings.placeholder}
400	                              spellCheck={false}
401	                            />
402	                            <span className="text-xs text-muted-foreground">
403	                              Example: <code>{providerSettings.example}</code>
404	                            </span>
405	                          </label>
406	
407	                          <Button
408	                            className="sm:mt-6"
409	                            type="button"
410	                            onClick={() => addCustomModel(provider)}
411	                          >
412	                            Add model
413	                          </Button>
414	                        </div>
415	
416	                        {customModelError ? (
417	                          <p className="text-xs text-destructive">{customModelError}</p>
418	                        ) : null}
419	
420	                        <div className="space-y-2">
421	                          <div className="flex items-center justify-between gap-2 text-xs text-muted-foreground">
422	                            <p>Saved custom models: {customModels.length}</p>
423	                            {customModels.length > 0 ? (
424	                              <Button
425	                                size="xs"
426	                                variant="outline"
427	                                onClick={() =>
428	                                  updateSettings(
429	                                    patchCustomModels(
430	                                      provider,
431	                                      [...getDefaultCustomModelsForProvider(defaults, provider)],
432	                                    ),
433	                                  )
434	                                }
435	                              >
436	                                Reset custom models
437	                              </Button>
438	                            ) : null}
439	                          </div>
440	
441	                          {customModels.length > 0 ? (
442	                            <div className="space-y-2">
443	                              {customModels.map((slug) => (
444	                                <div
445	                                  key={`${provider}:${slug}`}
446	                                  className="flex items-center justify-between gap-3 rounded-lg border border-border bg-background px-3 py-2"
447	                                >
448	                                  <div className="flex min-w-0 flex-1 items-center gap-2">
449	                                    {provider === "codex" && shouldShowFastTierIcon(slug, codexServiceTier) ? (
450	                                      <ZapIcon className="size-3.5 shrink-0 text-amber-500" />
451	                                    ) : null}
452	                                    <code className="min-w-0 flex-1 truncate text-xs text-foreground">
453	                                      {slug}
454	                                    </code>
455	                                  </div>
456	                                  <Button
457	                                    size="xs"
458	                                    variant="ghost"
459	                                    onClick={() => removeCustomModel(provider, slug)}
460	                                  >
461	                                    Remove
462	                                  </Button>
463	                                </div>
464	                              ))}
465	                            </div>
466	                          ) : (
467	                            <div className="rounded-lg border border-dashed border-border bg-background px-3 py-4 text-xs text-muted-foreground">
468	                              No custom models saved yet.
469	                            </div>
470	                          )}
471	                        </div>
472	                      </div>
473	                    </div>
474	                  );
475	                })}
476	              </div>
477	            </section>
478	
479	            <section className="rounded-2xl border border-border bg-card p-5">
480	              <div className="mb-4">
481	                <h2 className="text-sm font-medium text-foreground">Responses</h2>
482	                <p className="mt-1 text-xs text-muted-foreground">
483	                  Control how assistant output is rendered during a turn.
484	                </p>
485	              </div>
486	
487	              <div className="flex items-center justify-between rounded-lg border border-border bg-background px-3 py-2">
488	                <div>
489	                  <p className="text-sm font-medium text-foreground">Stream assistant messages</p>
