554	                ) : null}
555	              </div>
556	            </section>
557	
558	            <section className="rounded-2xl border border-border bg-card p-5">
559	              <div className="mb-4">
560	                <h2 className="text-sm font-medium text-foreground">Safety</h2>
561	                <p className="mt-1 text-xs text-muted-foreground">
562	                  Additional guardrails for destructive local actions.
563	                </p>
564	              </div>
565	
566	              <div className="flex items-center justify-between rounded-lg border border-border bg-background px-3 py-2">
567	                <div>
568	                  <p className="text-sm font-medium text-foreground">Confirm thread deletion</p>
569	                  <p className="text-xs text-muted-foreground">
570	                    Ask for confirmation before deleting a thread and its chat history.
571	                  </p>
572	                </div>
573	                <Switch
574	                  checked={settings.confirmThreadDelete}
