export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly isDark: boolean;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0a0a0b",
      foreground: "#e5e5e5",
      accent: "#6366f1",
      sidebar: "#111113",
      editor: "#0f0f11",
      terminal: "#09090b",
      statusBar: "#111113",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#1c1c22",
      accent: "#4f46e5",
      sidebar: "#f4f4f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#f4f4f5",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#0b1120",
      foreground: "#cbd5e1",
      accent: "#818cf8",
      sidebar: "#0f172a",
      editor: "#0d1424",
      terminal: "#080e1a",
      statusBar: "#0f172a",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
];

const themeMap = new Map<string, Theme>(
  BUILT_IN_THEMES.map((t) => [t.id, t]),
);

export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

