import { useCallback, useEffect, useSyncExternalStore } from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Mode management (light / dark / system)
// ---------------------------------------------------------------------------

type ThemeMode = "light" | "dark" | "system";
type ModeSnapshot = {
  mode: ThemeMode;
  systemDark: boolean;
};

const MODE_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let modeListeners: Array<() => void> = [];
let lastModeSnapshot: ModeSnapshot | null = null;

function emitModeChange() {
  for (const listener of modeListeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredMode(): ThemeMode {
  const raw = localStorage.getItem(MODE_STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function applyMode(mode: ThemeMode, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = mode === "dark" || (mode === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function getModeSnapshot(): ModeSnapshot {
  const mode = getStoredMode();
  const systemDark = mode === "system" ? getSystemDark() : false;

  if (lastModeSnapshot && lastModeSnapshot.mode === mode && lastModeSnapshot.systemDark === systemDark) {
    return lastModeSnapshot;
  }

  lastModeSnapshot = { mode, systemDark };
  return lastModeSnapshot;
}

function subscribeMode(listener: () => void): () => void {
  modeListeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredMode() === "system") applyMode("system", true);
    emitModeChange();
  };
  mq.addEventListener("change", handleChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === MODE_STORAGE_KEY) {
      applyMode(getStoredMode(), true);
      emitModeChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    modeListeners = modeListeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Custom theme management
// ---------------------------------------------------------------------------

const CUSTOM_THEME_STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID = "t3-dark";

let customThemeListeners: Array<() => void> = [];
let lastCustomThemeSnapshot: { themeId: string } | null = null;

function emitCustomThemeChange() {
  for (const listener of customThemeListeners) listener();
}

function getStoredThemeId(): string {
  try {
    const raw = localStorage.getItem(CUSTOM_THEME_STORAGE_KEY);
    if (raw && getTheme(raw)) return raw;
  } catch {
    // Ignore localStorage errors
  }
  return DEFAULT_THEME_ID;
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

function applyThemeCssProperties(theme: Theme): void {
  const style = document.documentElement.style;
  style.setProperty("--theme-background", theme.colors.background);
  style.setProperty("--theme-foreground", theme.colors.foreground);
  style.setProperty("--theme-accent", theme.colors.accent);
  style.setProperty("--theme-sidebar", theme.colors.sidebar);
  style.setProperty("--theme-editor", theme.colors.editor);
  style.setProperty("--theme-terminal", theme.colors.terminal);
  style.setProperty("--theme-status-bar", theme.colors.statusBar);
  style.setProperty("--theme-font-family", theme.fontFamily);
  style.setProperty("--theme-font-size", `${String(theme.fontSize)}px`);
}

function getCustomThemeSnapshot(): { themeId: string } {
  const themeId = getStoredThemeId();
  if (lastCustomThemeSnapshot && lastCustomThemeSnapshot.themeId === themeId) {
    return lastCustomThemeSnapshot;
  }
  lastCustomThemeSnapshot = { themeId };
  return lastCustomThemeSnapshot;
}

function subscribeCustomTheme(listener: () => void): () => void {
  customThemeListeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === CUSTOM_THEME_STORAGE_KEY) {
      const theme = resolveTheme(e.newValue ?? DEFAULT_THEME_ID);
      applyThemeCssProperties(theme);
      // Sync the mode to match the theme
      const nextMode: ThemeMode = theme.isDark ? "dark" : "light";
      localStorage.setItem(MODE_STORAGE_KEY, nextMode);
      applyMode(nextMode, true);
      emitModeChange();
      emitCustomThemeChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    customThemeListeners = customThemeListeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Apply stored preferences immediately on module load to prevent flash
// ---------------------------------------------------------------------------

const initialTheme = resolveTheme(getStoredThemeId());
applyThemeCssProperties(initialTheme);
applyMode(initialTheme.isDark ? "dark" : "light");

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

const availableThemes = listThemes();

export function useTheme() {
  // Mode state
  const modeSnapshot = useSyncExternalStore(subscribeMode, getModeSnapshot);
  const theme = modeSnapshot.mode;
  const resolvedTheme: "light" | "dark" =
    theme === "system" ? (modeSnapshot.systemDark ? "dark" : "light") : theme;

  const setTheme = useCallback((next: ThemeMode) => {
    localStorage.setItem(MODE_STORAGE_KEY, next);
    applyMode(next, true);
    emitModeChange();
  }, []);

  useEffect(() => {
    applyMode(theme);
  }, [theme]);

  // Custom theme state
  const customSnapshot = useSyncExternalStore(subscribeCustomTheme, getCustomThemeSnapshot);
  const activeTheme = resolveTheme(customSnapshot.themeId);

  const setActiveTheme = useCallback((id: string) => {
    const next = resolveTheme(id);
    try {
      localStorage.setItem(CUSTOM_THEME_STORAGE_KEY, next.id);
    } catch {
      // Ignore localStorage errors
    }
    applyThemeCssProperties(next);
    // Sync mode to match the selected theme
    const nextMode: ThemeMode = next.isDark ? "dark" : "light";
    localStorage.setItem(MODE_STORAGE_KEY, nextMode);
    applyMode(nextMode, true);
    emitModeChange();
    emitCustomThemeChange();
  }, []);

  useEffect(() => {
    applyThemeCssProperties(activeTheme);
  }, [activeTheme]);

  return {
    theme,
    setTheme,
    resolvedTheme,
    activeTheme,
    setActiveTheme,
    availableThemes,
  } as const;
}

