import { createContext, use, useMemo, type ReactNode } from "react";
import type { Theme } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";

export interface ThemeContextValue {
  /** The currently active custom theme. */
  readonly theme: Theme;
  /** Set the active custom theme by its id. */
  readonly setTheme: (id: string) => void;
  /** All available themes. */
  readonly availableThemes: readonly Theme[];
}

export const ThemeContext = createContext<ThemeContextValue | null>(null);

/**
 * Provides the custom theme context to the component tree.
 *
 * Wraps the module-level theme external store exposed by `useTheme` and
 * re-publishes it as React context so descendants can consume theme state
 * without calling the hook directly.
 */
export function ThemeProvider({ children }: { readonly children: ReactNode }) {
  const { activeTheme, setActiveTheme, availableThemes } = useTheme();

  const value = useMemo<ThemeContextValue>(
    () => ({
      theme: activeTheme,
      setTheme: setActiveTheme,
      availableThemes,
    }),
    [activeTheme, setActiveTheme, availableThemes],
  );

  return <ThemeContext value={value}>{children}</ThemeContext>;
}

/**
 * Consume the custom theme context provided by `ThemeProvider`.
 *
 * Must be called within a `ThemeProvider` — throws if the context is missing.
 */
export function useCustomTheme(): ThemeContextValue {
  const ctx = use(ThemeContext);
  if (!ctx) {
    throw new Error("useCustomTheme must be used within a <ThemeProvider>");
  }
  return ctx;
}

