import type { Theme } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({ theme }: { readonly theme: Theme }) {
  return (
    <div
      className="flex h-8 w-12 overflow-hidden rounded-md border border-border"
      aria-hidden="true"
    >
      <div className="flex-1" style={{ backgroundColor: theme.colors.sidebar }} />
      <div className="flex flex-[2] flex-col">
        <div className="flex-1" style={{ backgroundColor: theme.colors.editor }} />
        <div className="h-1.5" style={{ backgroundColor: theme.colors.statusBar }} />
      </div>
    </div>
  );
}

/**
 * Renders a list of available themes as selectable cards with color preview
 * swatches. Reads and writes theme state through the `useTheme` hook.
 */
export function ThemeSelector() {
  const { activeTheme, setActiveTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme">
      {availableThemes.map((t) => {
        const selected = activeTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setActiveTheme(t.id)}
          >
            <ThemeSwatch theme={t} />
            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="text-xs">
                {t.isDark ? "Dark" : "Light"} theme
                {" \u00b7 "}
                <span
                  className="inline-block size-2 rounded-full align-middle"
                  style={{ backgroundColor: t.colors.accent }}
                />{" "}
                accent
              </span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

